package main

import (
	"gno.land/r/gov/dao"
	"gno.land/r/sys/users"
)

func main(cur realm) {
	r := users.ProposeRegisterUser(cross(cur), "moul", address("g1manfred47kzduec920z88wfr64ylksmdcedlf5"))
	pid := dao.MustCreateProposal(cross(cur), r)
	dao.MustVoteOnProposalSimple(cross(cur), int64(pid), "YES")
	dao.ExecuteProposal(cross(cur), pid)
}
